// ViewController.swift
import UIKit
import GoogleMaps
import Stripe

class ViewController: UIViewController {
    var paymentSheet: PaymentSheet?

    override func viewDidLoad() {
        super.viewDidLoad()
        let mapView = GMSMapView(frame: view.bounds)
        view.addSubview(mapView)
        navigationItem.rightBarButtonItem = UIBarButtonItem(
            title: "Pay",
            style: .plain,
            target: self,
            action: #selector(payButtonTapped)
        )
    }

    @objc func payButtonTapped() {
        let paymentIntentClientSecret = "dummy_client_secret"
        var configuration = PaymentSheet.Configuration()
        configuration.merchantDisplayName = "Demo Investor App"
        paymentSheet = PaymentSheet(paymentIntentClientSecret: paymentIntentClientSecret, configuration: configuration)
        paymentSheet?.present(from: self) { paymentResult in
            switch paymentResult {
            case .completed:
                print("Payment complete!")
            case .canceled:
                print("Payment canceled!")
            case .failed(let error):
                print("Payment failed with error: \(error)")
            }
        }
    }
}

